import React, { useState, useMemo } from 'react';
import { Task, TaskStatus, User, Team } from '../types';
import { ChevronLeft, ChevronRight, Calendar as CalendarIcon, CheckCircle2, Clock, AlertCircle } from 'lucide-react';

interface CalendarViewProps {
  tasks: { [teamId: string]: Task[] };
  teams: Team[];
  users: User[];
}

const CalendarView: React.FC<CalendarViewProps> = ({ tasks, teams, users }) => {
  const [currentDate, setCurrentDate] = useState(new Date());

  const getDaysInMonth = (year: number, month: number) => new Date(year, month + 1, 0).getDate();
  const getFirstDayOfMonth = (year: number, month: number) => new Date(year, month, 1).getDay();

  const year = currentDate.getFullYear();
  const month = currentDate.getMonth();
  const daysInMonth = getDaysInMonth(year, month);
  const firstDay = getFirstDayOfMonth(year, month);

  const prevMonth = () => setCurrentDate(new Date(year, month - 1, 1));
  const nextMonth = () => setCurrentDate(new Date(year, month + 1, 1));

  // Flatten tasks into a single array with team info
  const allTasks = useMemo(() => {
    const flatTasks: (Task & { teamName: string, teamColor: string })[] = [];
    Object.entries(tasks).forEach(([teamId, teamTasks]) => {
      const team = teams.find(t => t.id === teamId);
      if (team) {
        // Generate a pseudo-random color based on team name length/char for consistency
        const colors = ['bg-blue-500', 'bg-green-500', 'bg-purple-500', 'bg-yellow-500', 'bg-pink-500', 'bg-indigo-500'];
        const color = colors[team.name.length % colors.length];

        teamTasks.forEach(task => {
            if (task.dueDate) {
                flatTasks.push({ ...task, teamName: team.name, teamColor: color });
            }
        });
      }
    });
    return flatTasks;
  }, [tasks, teams]);

  const tasksByDate = useMemo(() => {
    const grouped: { [date: string]: typeof allTasks } = {};
    allTasks.forEach(task => {
        if(task.dueDate) {
            // task.dueDate is YYYY-MM-DD string
            const dateKey = task.dueDate; 
            if (!grouped[dateKey]) grouped[dateKey] = [];
            grouped[dateKey].push(task);
        }
    });
    return grouped;
  }, [allTasks]);

  const renderCalendarDays = () => {
    const days = [];
    const emptyDays = firstDay; // 0 is Sunday

    for (let i = 0; i < emptyDays; i++) {
      days.push(<div key={`empty-${i}`} className="h-32 bg-gray-900/50 border border-gray-800"></div>);
    }

    for (let day = 1; day <= daysInMonth; day++) {
      const dateString = `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
      const dayTasks = tasksByDate[dateString] || [];
      const isToday = new Date().toDateString() === new Date(year, month, day).toDateString();

      days.push(
        <div key={day} className={`h-32 p-2 border border-gray-800 relative group overflow-hidden ${isToday ? 'bg-gray-800/50' : 'bg-gray-900 hover:bg-gray-800/30'}`}>
          <div className="flex justify-between items-start mb-1">
            <span className={`text-sm font-semibold h-7 w-7 flex items-center justify-center rounded-full ${isToday ? 'bg-primary-600 text-white' : 'text-gray-400'}`}>
                {day}
            </span>
            {dayTasks.length > 0 && <span className="text-xs text-gray-500">{dayTasks.length} tasks</span>}
          </div>

          <div className="space-y-1 overflow-y-auto max-h-[calc(100%-2rem)] custom-scrollbar">
            {dayTasks.map(task => (
                <div key={task.id} className={`text-xs p-1 rounded border-l-2 truncate ${task.teamColor} bg-gray-800 text-gray-200 border-opacity-70 bg-opacity-20`}>
                   {task.status === TaskStatus.DONE ? <CheckCircle2 className="inline h-3 w-3 mr-1 text-green-400"/> : null}
                   {task.title}
                </div>
            ))}
          </div>
        </div>
      );
    }

    return days;
  };

  return (
    <div className="flex flex-col h-full bg-gray-950 p-6 overflow-hidden">
      <div className="flex justify-between items-center mb-6">
        <div className="flex items-center space-x-4">
             <CalendarIcon className="h-8 w-8 text-primary-500" />
             <h1 className="text-2xl font-bold text-white">Global Calendar</h1>
        </div>
        <div className="flex items-center space-x-4">
          <button onClick={prevMonth} className="p-2 rounded-full hover:bg-gray-800 text-gray-400 hover:text-white">
            <ChevronLeft className="h-6 w-6" />
          </button>
          <span className="text-xl font-semibold text-white w-48 text-center">
            {currentDate.toLocaleDateString('en-US', { month: 'long', year: 'numeric' })}
          </span>
          <button onClick={nextMonth} className="p-2 rounded-full hover:bg-gray-800 text-gray-400 hover:text-white">
            <ChevronRight className="h-6 w-6" />
          </button>
        </div>
      </div>

      <div className="flex-1 flex flex-col min-h-0 border border-gray-800 rounded-lg overflow-hidden shadow-2xl">
        <div className="grid grid-cols-7 bg-gray-900 border-b border-gray-800">
          {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(d => (
            <div key={d} className="py-3 text-center text-sm font-semibold text-gray-400 uppercase tracking-wider">
              {d}
            </div>
          ))}
        </div>
        <div className="grid grid-cols-7 flex-1 overflow-y-auto">
          {renderCalendarDays()}
        </div>
      </div>
    </div>
  );
};

export default CalendarView;

import React from 'react';
import { User, Channel, Team, ChannelType } from '../types';
import { Hash, Megaphone, Settings, Plus, Calendar, MessageCircle } from 'lucide-react';

interface SidebarProps {
  clubName: string;
  currentUser: User;
  users: User[];
  channels: Channel[];
  teams: Team[];
  activeChannelId: string;
  activeViewType: string;
  onSelectChannel: (channelId: string) => void;
  onSelectCalendar: () => void;
  onOpenCreateTeamModal: () => void;
  onOpenMembersModal: () => void;
}

const Sidebar: React.FC<SidebarProps> = ({ 
    clubName, 
    currentUser, 
    users,
    channels, 
    teams, 
    activeChannelId, 
    activeViewType,
    onSelectChannel, 
    onSelectCalendar,
    onOpenCreateTeamModal,
    onOpenMembersModal
}) => {

  const renderChannelIcon = (channel: Channel) => {
    if (channel.type === ChannelType.ANNOUNCEMENTS) {
      return <Megaphone className="h-5 w-5 text-gray-400" />;
    }
    if (channel.type === ChannelType.GENERAL) {
      return <Hash className="h-5 w-5 text-gray-400" />;
    }
    if (channel.type === ChannelType.TEAM) {
      const team = teams.find(t => t.id === channel.teamId);
      const Icon = team?.icon;
      return Icon ? <Icon className="h-5 w-5 text-gray-400" /> : <Hash className="h-5 w-5 text-gray-400" />;
    }
    if (channel.type === ChannelType.DIRECT) {
        return <MessageCircle className="h-5 w-5 text-gray-400" />;
    }
    return null;
  };

  const getChannelDisplayName = (channel: Channel) => {
      if (channel.type === ChannelType.DIRECT && channel.memberIds) {
          const otherUserId = channel.memberIds.find(id => id !== currentUser.id);
          const otherUser = users.find(u => u.id === otherUserId);
          return otherUser ? otherUser.name : 'Unknown User';
      }
      return channel.name;
  }

  const teamChannels = channels.filter(c => c.type === ChannelType.TEAM);
  const generalChannels = channels.filter(c => c.type !== ChannelType.TEAM && c.type !== ChannelType.DIRECT);
  const directChannels = channels.filter(c => c.type === ChannelType.DIRECT);

  const canCreateTeam = ['Secretary', 'Coordinator', 'Joint Coordinator'].includes(currentUser.role);

  return (
    <div className="w-64 bg-gray-950 flex flex-col h-full border-r border-gray-800">
      <div className="p-4 border-b border-gray-800">
        <h1 className="text-xl font-bold text-white">Club Workspace</h1>
        <p className="text-sm text-gray-400 truncate">{clubName}</p>
      </div>

      <nav className="flex-1 overflow-y-auto p-4 space-y-4">
        <div>
          <h2 className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-2 px-2">General</h2>
          {generalChannels.map(channel => (
            <a
              key={channel.id}
              href="#"
              onClick={(e) => { e.preventDefault(); onSelectChannel(channel.id); }}
              className={`flex items-center space-x-3 px-2 py-2 rounded-md text-sm font-medium ${
                activeChannelId === channel.id && activeViewType === 'channel' ? 'bg-primary-600 text-white' : 'text-gray-300 hover:bg-gray-800 hover:text-white'
              }`}
            >
              {renderChannelIcon(channel)}
              <span>{channel.name}</span>
            </a>
          ))}
           <a
              href="#"
              onClick={(e) => { e.preventDefault(); onSelectCalendar(); }}
              className={`flex items-center space-x-3 px-2 py-2 rounded-md text-sm font-medium ${
                activeViewType === 'calendar' ? 'bg-primary-600 text-white' : 'text-gray-300 hover:bg-gray-800 hover:text-white'
              }`}
            >
              <Calendar className="h-5 w-5 text-gray-400" />
              <span>Calendar</span>
            </a>
        </div>

        <div>
           <div className="flex justify-between items-center mb-2 px-2">
              <h2 className="text-xs font-bold text-gray-500 uppercase tracking-wider">Teams</h2>
              {canCreateTeam && (
                <button onClick={onOpenCreateTeamModal} className="text-gray-400 hover:text-white p-1 rounded-full hover:bg-gray-700">
                  <Plus className="h-4 w-4" />
                </button>
              )}
            </div>
          {teamChannels.map(channel => (
            <a
              key={channel.id}
              href="#"
              onClick={(e) => { e.preventDefault(); onSelectChannel(channel.id); }}
              className={`flex items-center space-x-3 px-2 py-2 rounded-md text-sm font-medium ${
                activeChannelId === channel.id && activeViewType === 'channel' ? 'bg-primary-600 text-white' : 'text-gray-300 hover:bg-gray-800 hover:text-white'
              }`}
            >
              {renderChannelIcon(channel)}
              <span>{channel.name}</span>
            </a>
          ))}
        </div>

        <div>
           <div className="flex justify-between items-center mb-2 px-2">
              <h2 className="text-xs font-bold text-gray-500 uppercase tracking-wider">Direct Messages</h2>
               <button onClick={onOpenMembersModal} className="text-gray-400 hover:text-white p-1 rounded-full hover:bg-gray-700">
                  <Plus className="h-4 w-4" />
                </button>
            </div>
          {directChannels.map(channel => {
              const displayName = getChannelDisplayName(channel);
              const otherUserId = channel.memberIds?.find(id => id !== currentUser.id);
              const otherUser = users.find(u => u.id === otherUserId);

              return (
                <a
                key={channel.id}
                href="#"
                onClick={(e) => { e.preventDefault(); onSelectChannel(channel.id); }}
                className={`flex items-center space-x-3 px-2 py-2 rounded-md text-sm font-medium ${
                    activeChannelId === channel.id && activeViewType === 'channel' ? 'bg-primary-600 text-white' : 'text-gray-300 hover:bg-gray-800 hover:text-white'
                }`}
                >
                {otherUser ? (
                    <img src={otherUser.avatarUrl} alt={otherUser.name} className="h-5 w-5 rounded-full" />
                ) : (
                    <MessageCircle className="h-5 w-5 text-gray-400" />
                )}
                <span className="truncate">{displayName}</span>
                </a>
             );
          })}
        </div>
      </nav>

      <div className="p-4 border-t border-gray-800">
        <div className="flex items-center space-x-3">
          <img src={currentUser.avatarUrl} alt={currentUser.name} className="h-10 w-10 rounded-full" />
          <div className="flex-1 min-w-0">
            <p className="text-sm font-semibold text-white truncate">{currentUser.name}</p>
            <p className="text-xs text-gray-400 truncate">{currentUser.role}</p>
          </div>
          <div className="flex items-center text-gray-400">
             <Settings className="h-5 w-5 hover:text-white cursor-pointer"/>
          </div>
        </div>
      </div>
    </div>
  );
};

