import React, { useMemo } from 'react';
import { Channel, Team, User, ChannelType } from '../types';
import { Hash, MessageSquare, ListTodo, AppWindow, Menu, Users, MessageCircle } from 'lucide-react';

interface HeaderProps {
  channel?: Channel;
  team?: Team;
  activeViewType: 'channel' | 'tasks' | 'apps' | 'calendar';
  onViewChange: (viewType: 'channel' | 'tasks' | 'apps' | 'calendar') => void;
  currentUser: User;
  users: User[];
  onToggleSidebar: () => void;
  onOpenMembersModal: () => void;
}

const Header: React.FC<HeaderProps> = ({ channel, team, activeViewType, onViewChange, currentUser, users, onToggleSidebar, onOpenMembersModal }) => {

  const membersToDisplay = useMemo(() => {
    if (activeViewType === 'calendar') return users.slice(0, 5); // Just show some users for calendar
    if (!channel) return [];

    if (channel.type === ChannelType.DIRECT && channel.memberIds) {
         return users.filter(u => channel.memberIds?.includes(u.id));
    }
    if (team) {
      return users.filter(u => u.teamId === team.id);
    }
    // For general channels, show top leadership
    return users.filter(u => ['Secretary', 'Coordinator', 'Joint Coordinator'].includes(u.role));
  }, [team, users, channel, activeViewType]);

  const renderTitle = () => {
      if (activeViewType === 'calendar') {
          return (
             <div className="flex items-center space-x-2">
                <div className="h-6 w-6 text-primary-500 font-bold" /> 
                <h2 className="text-xl font-bold text-white">Calendar</h2>
            </div>
          )
      }
      if (!channel) return null;

      if (channel.type === ChannelType.DIRECT) {
          const otherUserId = channel.memberIds?.find(id => id !== currentUser.id);
          const otherUser = users.find(u => u.id === otherUserId);
          return (
            <div className="flex items-center space-x-2">
                {otherUser ? <img src={otherUser.avatarUrl} className="h-6 w-6 rounded-full" /> : <MessageCircle className="h-6 w-6 text-gray-400" />}
                <h2 className="text-xl font-bold text-white">{otherUser ? otherUser.name : 'Direct Message'}</h2>
            </div>
          )
      }

      return (
        <div className="flex items-center space-x-2">
            {team?.icon ? <team.icon className="h-6 w-6 text-gray-400" /> : <Hash className="h-6 w-6 text-gray-400" />}
            <h2 className="text-xl font-bold text-white">{channel.name}</h2>
        </div>
      );
  }

  return (
    <header className="flex-shrink-0 bg-gray-900 border-b border-gray-800 flex flex-col">
      <div className="flex items-center justify-between p-4 h-16">
        <div className="flex items-center space-x-3">
          <button onClick={onToggleSidebar} className="md:hidden p-2 -ml-2 text-gray-400 hover:text-white">
            <Menu className="h-6 w-6" />
          </button>
          {renderTitle()}
        </div>
        <div className="flex items-center space-x-4">
          <div className="flex -space-x-2 overflow-hidden">
             {membersToDisplay.slice(0, 3).map(user => (
               <img key={user.id} className="inline-block h-8 w-8 rounded-full ring-2 ring-gray-800" src={user.avatarUrl} alt={user.name} title={user.name} />
             ))}
             {membersToDisplay.length > 3 && (
               <div className="flex h-8 w-8 items-center justify-center rounded-full bg-gray-700 ring-2 ring-gray-800 text-xs font-medium text-gray-300">
                 +{membersToDisplay.length - 3}
               </div>
             )}
          </div>
          {activeViewType !== 'calendar' && (
              <button onClick={onOpenMembersModal} className="flex items-center space-x-2 bg-gray-800 hover:bg-gray-700 text-white font-semibold py-2 px-3 rounded-md text-sm">
                 <Users className="h-4 w-4"/>
                 <span className="hidden sm:inline">Members</span>
              </button>
          )}
        </div>
      </div>

      {team && activeViewType !== 'calendar' && channel?.type === ChannelType.TEAM && (
        <div className="px-4">
          <div className="flex border-b border-gray-800">
            <TabButton icon={MessageSquare} label="Chat" active={activeViewType === 'channel'} onClick={() => onViewChange('channel')} />
            <TabButton icon={ListTodo} label="Tasks" active={activeViewType === 'tasks'} onClick={() => onViewChange('tasks')} />
            <TabButton icon={AppWindow} label="Apps & Tools" active={activeViewType === 'apps'} onClick={() => onViewChange('apps')} />
          </div>
        </div>
      )}
    </header>
  );
};


interface TabButtonProps {
    icon: React.ElementType;
    label: string;
    active: boolean;
    onClick: () => void;
}

const TabButton: React.FC<TabButtonProps> = ({ icon: Icon, label, active, onClick}) => {
    return (
        <button
          onClick={onClick}
          className={`flex items-center space-x-2 px-4 py-3 text-sm font-medium border-b-2 transition-colors duration-200
            ${active 
              ? 'border-primary-500 text-primary-500' 
              : 'border-transparent text-gray-400 hover:text-white hover:border-gray-500'
            }
          `}
        >
          <Icon className="h-5 w-5"/>
          <span>{label}</span>
        </button>
    )
}


export default Header;

import React, { useState, useMemo } from 'react';
import { User, Role, Team } from '../types';
import { X, Send, MessageCircle } from 'lucide-react';

interface MembersModalProps {
  isOpen: boolean;
  onClose: () => void;
  currentUser: User;
  users: User[];
  onInviteUser: (email: string) => void;
  onUpdateUserRole: (userId: string, newRole: Role) => void;
  onMessageUser: (userId: string) => void;
  team?: Team; // The currently active team, if any
  teams: Team[]; // All teams
}

const ROLES_HIERARCHY: Role[] = ['Secretary', 'Coordinator', 'Joint Coordinator', 'Team Head', 'Team Co-Head', 'Member'];

const MembersModal: React.FC<MembersModalProps> = ({ isOpen, onClose, currentUser, users, onInviteUser, onUpdateUserRole, onMessageUser, team, teams }) => {
  const [inviteEmail, setInviteEmail] = useState('');

  const handleInvite = (e: React.FormEvent) => {
    e.preventDefault();
    if (inviteEmail.trim()) {
      onInviteUser(inviteEmail);
      setInviteEmail('');
    }
  };

  const canEdit = (targetUser: User): boolean => {
    if (currentUser.id === targetUser.id) return false;
    if (currentUser.role === 'Secretary') return true;
    return false;
  };

  const getDesignation = (user: User): string => {
    if ((user.role === 'Team Head' || user.role === 'Team Co-Head') && user.teamId) {
        const teamName = teams.find(t => t.id === user.teamId)?.name;
        return teamName ? `${teamName} ${user.role}` : user.role;
    }
    return user.role;
  }

  const usersToDisplay = useMemo(() => {
      const userList = team ? users.filter(u => u.teamId === team.id) : users;
      return [...userList].sort((a, b) => ROLES_HIERARCHY.indexOf(a.role) - ROLES_HIERARCHY.indexOf(b.role));
  }, [users, team]);


  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-gray-950 bg-opacity-80 flex items-center justify-center z-50 p-4">
      <div className="bg-gray-800 rounded-lg p-6 w-full max-w-2xl border border-gray-700 shadow-xl flex flex-col max-h-[90vh]">
        <div className="flex justify-between items-center mb-4 flex-shrink-0">
          <h2 className="text-2xl font-bold text-white">{team ? `${team.name} Members` : 'Club Members'}</h2>
          <button onClick={onClose} className="p-1 rounded-full hover:bg-gray-700">
            <X className="h-6 w-6 text-gray-400" />
          </button>
        </div>

        {currentUser.role === 'Secretary' && !team && (
          <form onSubmit={handleInvite} className="flex items-center space-x-2 mb-6 flex-shrink-0">
            <input
              type="email"
              placeholder="Invite new member by email..."
              value={inviteEmail}
              onChange={(e) => setInviteEmail(e.target.value)}
              className="flex-1 bg-gray-900 rounded-md py-2 px-3 border border-gray-600 focus:ring-1 focus:ring-primary-500 focus:border-primary-500 text-white placeholder-gray-500"
            />
            <button type="submit" className="flex items-center space-x-2 bg-primary-600 hover:bg-primary-700 text-white font-semibold py-2 px-4 rounded-md disabled:bg-gray-600" disabled={!inviteEmail}>
              <Send className="h-4 w-4" />
              <span>Invite</span>
            </button>
          </form>
        )}

        <div className="overflow-y-auto pr-2 -mr-2">
          <div className="space-y-3">
            {usersToDisplay.map(user => (
              <div key={user.id} className="flex items-center justify-between bg-gray-900/50 p-3 rounded-md group hover:bg-gray-800 transition-colors">
                <div className="flex items-center space-x-3">
                  <img src={user.avatarUrl} alt={user.name} className="h-10 w-10 rounded-full" />
                  <div>
                    <p className="font-semibold text-white flex items-center gap-2">
                        {user.name}
                         {user.id === currentUser.id && <span className="text-xs text-gray-500">(You)</span>}
                    </p>
                    <p className="text-xs text-gray-400">{user.email || 'No email'}</p>
                  </div>
                </div>
                <div className="flex items-center space-x-3">
                  {user.id !== currentUser.id && (
                       <button onClick={() => onMessageUser(user.id)} className="p-2 text-gray-400 hover:text-white bg-gray-800 hover:bg-gray-700 rounded-full transition-colors" title="Send Direct Message">
                          <MessageCircle className="h-4 w-4" />
                       </button>
                  )}
                  {canEdit(user) ? (
                    <select
                      value={user.role}
                      onChange={(e) => onUpdateUserRole(user.id, e.target.value as Role)}
                      className="bg-gray-700 text-white text-sm rounded-md py-1 px-2 border border-gray-600 focus:ring-1 focus:ring-primary-500"
                    >
                      {ROLES_HIERARCHY.map(role => (
                         !['Team Head', 'Team Co-Head'].includes(role) && <option key={role} value={role}>{role}</option>
                      ))}
                    </select>
                  ) : (
                     <span className="text-sm font-medium text-gray-300 bg-gray-700 px-3 py-1 rounded-full">{getDesignation(user)}</span>
                  )}
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

